$ErrorActionPreference = 'Stop'
$utf8 = [System.Text.UTF8Encoding]::new($false)
$nl = [Environment]::NewLine

function Change($id, $phase, $name, $owner, $reviewer, $deps, $why, $scope, $refs, $requirements, $design, $checks) {
    [pscustomobject]@{
        Id = $id; Phase = $phase; Name = $name; Owner = $owner; Reviewer = $reviewer; Dependencies = $deps
        Why = $why; Scope = $scope; References = $refs; Requirements = $requirements; Design = $design; Checks = $checks
    }
}

