function WriteText($path, $lines) {
    $parent = Split-Path -Parent $path
    New-Item -ItemType Directory -Force -Path $parent | Out-Null
    $flat = @()
    foreach ($line in $lines) {
        if ($line -is [array]) { $flat += $line } else { $flat += $line }
    }
    [System.IO.File]::WriteAllText($path, ($flat -join $nl) + $nl, $utf8)
}

function GenerateProject($project, $changes) {
    $root = (Resolve-Path $project).Path
    $changeRoot = Join-Path $root 'openspec\changes'
    if (-not $changeRoot.StartsWith($root)) { throw "Ruta insegura: $changeRoot" }
    if (Test-Path $changeRoot) { Remove-Item -LiteralPath $changeRoot -Recurse -Force }
    New-Item -ItemType Directory -Force -Path $changeRoot | Out-Null

    foreach ($c in $changes) {
        $dir = Join-Path $changeRoot $c.Name
        $relativeRefs = $c.References | ForEach-Object { '- `../../../../{0}`' -f $_ }
        WriteText (Join-Path $dir 'proposal.md') @(
            "# Proposal: $($c.Name)", '', "**ID:** $($c.Id)  ", "**Fase:** $($c.Phase)  ", "**Owner:** $($c.Owner)  ",
            "**Reviewer:** $($c.Reviewer)  ", "**Dependencias:** $($c.Dependencies)", '', '## Why', '', $c.Why, '',
            '## In Scope', '', ($c.Scope | ForEach-Object { "- $_" }), '', '## Out of Scope', '',
            '- Capacidades pertenecientes a otros changes.', '- Cambiar reglas compartidas sin actualizar `docs/`.', '',
            '## Impact', '', ('- Proyecto: `{0}`.' -f $project), "- Capacidades: $($c.Scope -join ', ').", '', '## Source Documents', '', $relativeRefs
        )
        WriteText (Join-Path $dir 'design.md') @(
            "# Design: $($c.Name)", '', '## Sources and Invariants', '', ($c.References | ForEach-Object { '- `../../../../{0}`' -f $_ }), '',
            '## Technical Design', '', ($c.Design | ForEach-Object { "- $_." }), '', '## Security and Authorization', '',
            '- Laravel sigue siendo autoridad de permisos y reglas críticas.', '- Aplicar mínimo privilegio, auditoría y protección de datos según los documentos fuente.', '',
            '## Testing Strategy', '', ($c.Checks | ForEach-Object { "- $_." }), '', '## Rejected Scope', '',
            '- No implementar capacidades declaradas en otros changes.', '- No depender de changes activos de otro proyecto como contrato estable.'
        )
        $taskNumber = 1
        $taskLines = @("# Tasks: $($c.Name)", '', '## Implementation')
        foreach ($item in $c.Design) { $taskLines += "- [ ] 1.$taskNumber $item. Owner: $($c.Owner)"; $taskNumber++ }
        $checkNumber = 1
        $taskLines += '', '## Verification'
        foreach ($item in $c.Checks) { $taskLines += "- [ ] 2.$checkNumber Verificar que $item. Owner: $($c.Owner)"; $checkNumber++ }
        $taskLines += '', '## Review and Archive', "- [ ] 3.1 Publicar contratos/documentación afectados. Owner: $($c.Owner)", "- [ ] 3.2 Revisar y archivar la spec aceptada. Reviewer: $($c.Reviewer)"
        WriteText (Join-Path $dir 'tasks.md') $taskLines

        WriteText (Join-Path $dir 'verification.md') @(
            "# Verification: $($c.Name)", '', '## Automated and Manual Checks', '', ($c.Checks | ForEach-Object { "- [ ] $_." }), '',
            '## Required Evidence', '', '- [ ] Resultados de pruebas o comandos adjuntos.', '- [ ] Escenarios de la delta spec demostrados.',
            '- [ ] Permisos negativos y datos sensibles revisados.', '- [ ] Contrato y documentos sincronizados.', '', '## Results', '', 'Pendiente durante la ejecución del change.'
        )
        $spec = @("# $($c.Name) Specification", '', '## Purpose', '', $c.Why, '', '## ADDED Requirements', '')
        $ri = 1
        foreach ($r in $c.Requirements) {
            $parts = $r -split '\|'
            $spec += "### Requirement $ri", '', $parts[0], '', "#### Scenario: $($parts[3])", '', "- GIVEN $($parts[1])", "- WHEN $($parts[2])", "- THEN $($parts[3])", ''
            $ri++
        }
        WriteText (Join-Path $dir "specs\$($c.Name)\spec.md") $spec
    }

    $plan = @("# $([cultureinfo]::CurrentCulture.TextInfo.ToTitleCase($project)) Execution Plan", '', '## Leyenda', '', '- `[ ]` pendiente', '- `[~]` en progreso', '- `[-]` bloqueado', '- `[x]` terminado, verificado y archivado', '')
    foreach ($phase in ($changes | Select-Object -ExpandProperty Phase -Unique)) {
        $plan += "## $phase", '', '| ID | Status | Change | Owner | Reviewer | Dependencies |', '|---|---|---|---|---|---|'
        foreach ($c in $changes | Where-Object Phase -eq $phase) { $plan += ('| {0} | `[ ]` | `{1}` | {2} | {3} | {4} |' -f $c.Id, $c.Name, $c.Owner, $c.Reviewer, $c.Dependencies) }
        $plan += ''
    }
    $plan += '## Regla de ejecución', '', 'Cada change se detalla desde sus documentos fuente antes de implementarse. No se inicia un change bloqueado ni se archiva sin demostrar todos sus escenarios.'
    WriteText (Join-Path $root 'openspec\EXECUTION_PLAN.md') $plan
}

GenerateProject 'backend' $backend
GenerateProject 'frontend' $frontend
